"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[402],{6939:(e,n,s)=>{s.r(n),s.d(n,{data:()=>a});const a={key:"v-38469734",path:"/guide/js/js%E7%AE%97%E6%B3%95.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"106、shuffle",slug:"_106、shuffle",children:[]},{level:2,title:"109、smoothScroll",slug:"_109、smoothscroll",children:[]},{level:2,title:"110、sortCharactersInString 此段代码将单词的内容按照字母的顺序进行重新排序。",slug:"_110、sortcharactersinstring-此段代码将单词的内容按照字母的顺序进行重新排序。",children:[]},{level:2,title:"113、sum 此段代码用于计算数字之和。",slug:"_113、sum-此段代码用于计算数字之和。",children:[]},{level:2,title:"115、take 从数组开始位置截取n个元素，生成新的数组。",slug:"_115、take-从数组开始位置截取n个元素-生成新的数组。",children:[]},{level:2,title:"116、takeRight",slug:"_116、takeright",children:[]},{level:2,title:"117、timeTaken 用来计算函数执行的时间。",slug:"_117、timetaken-用来计算函数执行的时间。",children:[]},{level:2,title:"118、times",slug:"_118、times",children:[]},{level:2,title:"119、toCurrency 此段代码用于按照指定的货币类型格式化货币数字。",slug:"_119、tocurrency-此段代码用于按照指定的货币类型格式化货币数字。",children:[]},{level:2,title:"120、toDecimalMark",slug:"_120、todecimalmark",children:[]},{level:2,title:"121、toggleClass 使用 element.classList.toggle() 来切换元素中指定样式类。",slug:"_121、toggleclass-使用-element-classlist-toggle-来切换元素中指定样式类。",children:[]},{level:2,title:"122、tomorrow",slug:"_122、tomorrow",children:[]},{level:2,title:"123、unfold 基于初始值，和步长生成一个新的数组。",slug:"_123、unfold-基于初始值-和步长生成一个新的数组。",children:[]},{level:2,title:"124、union",slug:"_124、union",children:[]},{level:2,title:"125、uniqueElements 使用 ES6 的 set 和 …rest 运算去除数组中重复的元素。",slug:"_125、uniqueelements-使用-es6-的-set-和-rest-运算去除数组中重复的元素。",children:[]},{level:2,title:"126. validateNumber",slug:"_126-validatenumber",children:[]},{level:2,title:"127. words 将一段英文字符串拆分成单词数组（去除一些特殊符号）。",slug:"_127-words-将一段英文字符串拆分成单词数组-去除一些特殊符号-。",children:[]},{level:2,title:"128 . 在网页上获取选定的文本",slug:"_128-在网页上获取选定的文本",children:[]}],filePathRelative:"guide/js/js算法.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},3924:(e,n,s)=>{s.r(n),s.d(n,{default:()=>i});var a=s(6252);const l={href:"https://www.toutiao.com/article/6803302196621345283/?app=news_article_lite&timestamp=1650465865&use_new_style=1&req_id=202204202244250101581560120814DBBA&group_id=6803302196621345283&share_token=38032DE7-1B79-43AF-B567-79FD5E676E50",target:"_blank",rel:"noopener noreferrer"},r=(0,a.uE)('<h2 id="_106、shuffle" tabindex="-1"><a class="header-anchor" href="#_106、shuffle" aria-hidden="true">#</a> 106、shuffle</h2><p>使用 Fisher–Yates shuffle 洗牌算法对数组的内容进行随机排序，生成新的数组。</p><p>什么是 Fisher–Yates shuffle 洗牌算法? 算法是一个用来将一个有限集合生成一个随机排列的算法（数组随机排序）。这个算法生成的随机排列是等概率的。同时这个算法非常高效。</p><p>更多关于 Fisher–Yates shuffle 洗牌算法的内容，你可以查看</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const shuffle = ([...arr]) =&gt; {\nlet m = arr.length;\nwhile (m) {\nconst i = Math.floor(Math.random() * m--);\n[arr[m], arr[i]] = [arr[i], arr[m]];\n}\nreturn arr;\n};\n\nconst foo = [1, 2, 3];\nshuffle(foo); // [2, 3, 1], foo = [1, 2, 3]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>107、similarity 查找两个数组之间的交集。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const similarity = (arr, values) =&gt; arr.filter(v =&gt; values.includes(v));\n\nsimilarity([1, 2, 3], [1, 2, 4]); // [1, 2]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>108、sleep 用于延迟异步函数的执行。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const sleep = ms =&gt; new Promise(resolve =&gt; setTimeout(resolve, ms));\n\nasync function sleepyWork() {\nconsole.log(&quot;I&#39;m going to sleep for 1 second.&quot;);\nawait sleep(1000);\nconsole.log(&#39;I woke up after 1 second.&#39;);\n}\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="_109、smoothscroll" tabindex="-1"><a class="header-anchor" href="#_109、smoothscroll" aria-hidden="true">#</a> 109、smoothScroll</h2><p>此段代码用于让指定的DOM节点平滑滚动到可视区域。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const smoothScroll = element =&gt;\ndocument.querySelector(element).scrollIntoView({ behavior: &#39;smooth&#39; });\n\nsmoothScroll(&#39;#fooBar&#39;); // scrolls smoothly to the element with the id fooBar smoothScroll(&#39;.fooBar&#39;); // scrolls smoothly to the first element with a class of fooBar\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_110、sortcharactersinstring-此段代码将单词的内容按照字母的顺序进行重新排序。" tabindex="-1"><a class="header-anchor" href="#_110、sortcharactersinstring-此段代码将单词的内容按照字母的顺序进行重新排序。" aria-hidden="true">#</a> 110、sortCharactersInString 此段代码将单词的内容按照字母的顺序进行重新排序。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const sortCharactersInString = str =&gt; [...str].sort((a, b) =&gt; a.localeCompare(b)).join(&#39;&#39;);\n\nsortCharactersInString(&#39;cabbage&#39;);\n\n// &#39;aabbceg&#39;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>111、splitLines 用于将一段字符串按照”换行符“分割成数组进行输出。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const splitLines = str =&gt; str.split(/\\r?\\n/);\nsplitLines(&#39;This\\nis a\\nmultiline\\nstring.\\n&#39;);\n// [&#39;This&#39;, &#39;is a&#39;, &#39;multiline&#39;, &#39;string.&#39; , &#39;&#39;]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>112、tripHTMLTags 格式化去掉 HTML 代码内容，输出文本内容。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const stripHTMLTags = str =&gt; str.replace(/&lt;[^&gt;]*&gt;/g, &#39;&#39;);\n\nstripHTMLTags(&#39;&lt;p&gt;&lt;em&gt;lorem&lt;/em&gt; &lt;strong&gt;ipsum&lt;/strong&gt;&lt;/p&gt;&#39;); // &#39;lorem ipsum&#39;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="_113、sum-此段代码用于计算数字之和。" tabindex="-1"><a class="header-anchor" href="#_113、sum-此段代码用于计算数字之和。" aria-hidden="true">#</a> 113、sum 此段代码用于计算数字之和。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const sum = (...arr) =&gt; [...arr].reduce((acc, val) =&gt; acc + val, 0);\n\nsum(1, 2, 3, 4); // 10\nsum(...[1, 2, 3, 4]); // 10\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>114、tail 用于获取数组除第一个元素之外的所有元素，如果数组只有一个元素，则返回本数组。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const tail = arr =&gt; (arr.length &gt; 1 ? arr.slice(1) : arr);\n\ntail([1, 2, 3]); // [2,3]\ntail([1]); // [1]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_115、take-从数组开始位置截取n个元素-生成新的数组。" tabindex="-1"><a class="header-anchor" href="#_115、take-从数组开始位置截取n个元素-生成新的数组。" aria-hidden="true">#</a> 115、take 从数组开始位置截取n个元素，生成新的数组。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const take = (arr, n = 1) =&gt; arr.slice(0, n);\n\ntake([1, 2, 3], 5); // [1, 2, 3]\ntake([1, 2, 3], 0); // []\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_116、takeright" tabindex="-1"><a class="header-anchor" href="#_116、takeright" aria-hidden="true">#</a> 116、takeRight</h2><p>从数组开始末尾截取n个元素，生成新的数组。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nconst takeRight = (arr, n = 1) =&gt; arr.slice(arr.length - n, arr.length);\n\ntakeRight([1, 2, 3], 2); // [ 2, 3 ]\ntakeRight([1, 2, 3]); // [3]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="_117、timetaken-用来计算函数执行的时间。" tabindex="-1"><a class="header-anchor" href="#_117、timetaken-用来计算函数执行的时间。" aria-hidden="true">#</a> 117、timeTaken 用来计算函数执行的时间。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const timeTaken = callback =&gt; {\nconsole.time(&#39;timeTaken&#39;);\nconst r = callback();\nconsole.timeEnd(&#39;timeTaken&#39;);\nreturn r;\n};\n\ntimeTaken(() =&gt; Math.pow(2, 10));\n// 1024, (logged): timeTaken: 0.02099609375ms\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="_118、times" tabindex="-1"><a class="header-anchor" href="#_118、times" aria-hidden="true">#</a> 118、times</h2><p>按照指定的次数，进行回调函数。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nconst times = (n, fn, context = undefined) =&gt; { let i = 0; while (fn.call(context, i) !== false &amp;&amp; ++i &lt; n) {} };\n\nvar output = &#39;&#39;; times(5, i =&gt; (output += i)); console.log(output); // 01234\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_119、tocurrency-此段代码用于按照指定的货币类型格式化货币数字。" tabindex="-1"><a class="header-anchor" href="#_119、tocurrency-此段代码用于按照指定的货币类型格式化货币数字。" aria-hidden="true">#</a> 119、toCurrency 此段代码用于按照指定的货币类型格式化货币数字。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const toCurrency = (n, curr, LanguageFormat = undefined) =&gt;\nIntl.NumberFormat(LanguageFormat, { style: &#39;currency&#39;, currency: curr }).format(n);\n\ntoCurrency(123456.789, &#39;EUR&#39;);\n// €123,456.79  | currency: Euro | currencyLangFormat: Local\ntoCurrency(123456.789, &#39;USD&#39;, &#39;en-us&#39;);\n// $123,456.79  | currency: US Dollar | currencyLangFormat: English (United States)\ntoCurrency(123456.789, &#39;USD&#39;, &#39;fa&#39;);\n// ۱۲۳٬۴۵۶٫۷۹ ؜$ | currency: US Dollar | currencyLangFormat: Farsi\ntoCurrency(322342436423.2435, &#39;JPY&#39;);\n// ¥322,342,436,423 | currency: Japanese Yen | currencyLangFormat: Local\ntoCurrency(322342436423.2435, &#39;JPY&#39;, &#39;fi&#39;);\n// 322 342 436 423 ¥ | currency: Japanese Yen | currencyLangFormat: Finnish\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="_120、todecimalmark" tabindex="-1"><a class="header-anchor" href="#_120、todecimalmark" aria-hidden="true">#</a> 120、toDecimalMark</h2><p>用于格式化数字，将其转换成逗号分隔的数字字符串。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nconst toDecimalMark = num =&gt; num.toLocaleString(&#39;en-US&#39;);\n\ntoDecimalMark(12305030388.9087); // &quot;12,305,030,388.909&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_121、toggleclass-使用-element-classlist-toggle-来切换元素中指定样式类。" tabindex="-1"><a class="header-anchor" href="#_121、toggleclass-使用-element-classlist-toggle-来切换元素中指定样式类。" aria-hidden="true">#</a> 121、toggleClass 使用 element.classList.toggle() 来切换元素中指定样式类。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const toggleClass = (el, className) =&gt; el.classList.toggle(className);\n\ntoggleClass(document.querySelector(&#39;p.special&#39;), &#39;special&#39;);\n// The paragraph will not have the &#39;special&#39; class anymore\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_122、tomorrow" tabindex="-1"><a class="header-anchor" href="#_122、tomorrow" aria-hidden="true">#</a> 122、tomorrow</h2><p>用于获取明天的日期。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nconst tomorrow = () =&gt; { let t = new Date(); t.setDate(t.getDate() + 1); return t.toISOString().split(&#39;T&#39;)[0]; };\n\ntomorrow(); // 2019-09-08 (if current date is 2018-09-08)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_123、unfold-基于初始值-和步长生成一个新的数组。" tabindex="-1"><a class="header-anchor" href="#_123、unfold-基于初始值-和步长生成一个新的数组。" aria-hidden="true">#</a> 123、unfold 基于初始值，和步长生成一个新的数组。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const unfold = (fn, seed) =&gt; {\nlet result = [],\nval = [null, seed];\nwhile ((val = fn(val[1]))) result.push(val[0]);\nreturn result;\n};\n\nvar f = n =&gt; (n &gt; 50 ? false : [-n, n + 10]);\nunfold(f, 10);\n// [-10, -20, -30, -40, -50]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="_124、union" tabindex="-1"><a class="header-anchor" href="#_124、union" aria-hidden="true">#</a> 124、union</h2><p>合并两个数组，并删除重复的内容。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nconst union = (a, b) =&gt; Array.from(new Set([...a, ...b])); union([1, 2, 3], [4, 3, 2]); // [1,2,3,4]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="_125、uniqueelements-使用-es6-的-set-和-rest-运算去除数组中重复的元素。" tabindex="-1"><a class="header-anchor" href="#_125、uniqueelements-使用-es6-的-set-和-rest-运算去除数组中重复的元素。" aria-hidden="true">#</a> 125、uniqueElements 使用 ES6 的 set 和 …rest 运算去除数组中重复的元素。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>onst uniqueElements = arr =&gt; [...new Set(arr)];\n\nuniqueElements([1, 2, 2, 3, 4, 4, 5]);\n// [1, 2, 3, 4, 5]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_126-validatenumber" tabindex="-1"><a class="header-anchor" href="#_126-validatenumber" aria-hidden="true">#</a> 126. validateNumber</h2><pre><code> 用于检查参数类型是否是数字。\n</code></pre><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\nconst validateNumber = n =&gt; !isNaN(parseFloat(n)) &amp;&amp; isFinite(n) &amp;&amp; Number(n) == n;\n\nvalidateNumber(&#39;10&#39;); // true\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="_127-words-将一段英文字符串拆分成单词数组-去除一些特殊符号-。" tabindex="-1"><a class="header-anchor" href="#_127-words-将一段英文字符串拆分成单词数组-去除一些特殊符号-。" aria-hidden="true">#</a> 127. words 将一段英文字符串拆分成单词数组（去除一些特殊符号）。</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>const words = (str, pattern = /[^a-zA-Z-]+/) =&gt; str.split(pattern).filter(Boolean);\n\nwords(&#39;I love javaScript!!&#39;);\n// [&quot;I&quot;, &quot;love&quot;, &quot;javaScript&quot;]\nwords(&#39;python, javaScript &amp; coffee&#39;);\n// [&quot;python&quot;, &quot;javaScript&quot;, &quot;coffee&quot;]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="_128-在网页上获取选定的文本" tabindex="-1"><a class="header-anchor" href="#_128-在网页上获取选定的文本" aria-hidden="true">#</a> 128 . 在网页上获取选定的文本</h2><blockquote><p>浏览器在全局窗口对象上有一个名为 getSelection 的内置方法。使用此方法，你可以创建一个单行，返回网页上突出显示或选定的文本。</p></blockquote><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> <span class="token function-variable function">getSelectedText</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> window<span class="token punctuation">.</span><span class="token function">getSelection</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',57),t={},i=(0,s(3744).Z)(t,[["render",function(e,n){const s=(0,a.up)("OutboundLink");return(0,a.wg)(),(0,a.iD)(a.HY,null,[(0,a._)("p",null,[(0,a._)("a",l,[(0,a.Wm)(s)])]),r],64)}]])},3744:(e,n)=>{n.Z=(e,n)=>{const s=e.__vccOpts||e;for(const[e,a]of n)s[e]=a;return s}}}]);